import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Arrays;
import java.util.List;

public class ImageConverter {
    
    public static boolean convertImage(String inputFilename, String outputFilename, String format) {
        try {
            // Validate input parameters
            if (inputFilename == null || inputFilename.trim().isEmpty() ||
                outputFilename == null || outputFilename.trim().isEmpty() ||
                format == null || format.trim().isEmpty()) {
                throw new IllegalArgumentException("Input parameters cannot be null or empty");
            }
            
            // Validate file extensions
            if (!isValidFileExtension(inputFilename)) {
                throw new IllegalArgumentException("Invalid input file extension");
            }
            
            if (!isValidFileExtension(outputFilename)) {
                throw new IllegalArgumentException("Invalid output file extension");
            }
            
            // Validate format
            if (!isValidFormat(format)) {
                throw new IllegalArgumentException("Invalid output format");
            }
            
            // Check if input file exists
            File inputFile = new File(inputFilename);
            if (!inputFile.exists()) {
                throw new IOException("Input file does not exist: " + inputFilename);
            }
            
            // Build command with validation
            List<String> command = Arrays.asList("convert", inputFilename, "-define", "png:color-type=6", 
                                                "-define", "png:compression-level=9", 
                                                "-define", "png:compression-filter=5", 
                                                "-define", "png:compression-strategy=1",
                                                "." + format, outputFilename);
            
            // Execute command
            ProcessBuilder processBuilder = new ProcessBuilder(command);
            processBuilder.redirectErrorStream(true);
            Process process = processBuilder.start();
            
            int exitCode = process.waitFor();
            
            if (exitCode != 0) {
                throw new IOException("ImageMagick conversion failed with exit code: " + exitCode);
            }
            
            // Verify output file was created
            File outputFile = new File(outputFilename);
            if (!outputFile.exists()) {
                throw new IOException("Output file was not created: " + outputFilename);
            }
            
            return true;
            
        } catch (Exception e) {
            System.err.println("Error converting image: " + e.getMessage());
            return false;
        }
    }
    
    private static boolean isValidFileExtension(String filename) {
        if (filename == null || filename.isEmpty()) {
            return false;
        }
        
        String lowerFilename = filename.toLowerCase();
        return lowerFilename.endsWith(".jpg") || lowerFilename.endsWith(".jpeg") || 
               lowerFilename.endsWith(".png") || lowerFilename.endsWith(".gif") ||
               lowerFilename.endsWith(".bmp") || lowerFilename.endsWith(".tiff") ||
               lowerFilename.endsWith(".webp") || lowerFilename.endsWith(".svg");
    }
    
    private static boolean isValidFormat(String format) {
        if (format == null || format.trim().isEmpty()) {
            return false;
        }
        
        String lowerFormat = format.toLowerCase().trim();
        return lowerFormat.equals("jpg") || lowerFormat.equals("jpeg") || 
               lowerFormat.equals("png") || lowerFormat.equals("gif") ||
               lowerFormat.equals("bmp") || lowerFormat.equals("tiff") ||
               lowerFormat.equals("webp") || lowerFormat.equals("svg");
    }
}